// GENERATED — do not edit by hand. Real Earth elevation, baked for the 'earth'
// landform. Equirectangular 2048x1024 grayscale (native source resolution, ~19km
// per cell at the equator): ocean = 0, land ramps 1..255 with real elevation.
// North up; left edge is the mid-Pacific antimeridian. Source: three-globe's
// earth-topology displacement map (github.com/vasturiano/three-globe, MIT),
// derived from NASA/NOAA public topography. Stored gzip-compressed (raw grid is
// 2 MB; gzip is ~370 KB) and decoded with DecompressionStream, so small features
// like Florida and the world's peninsulas survive (batch 70; the old 512x256
// bake eroded them). Lazy-imported: only an 'earth' world pulls this chunk.

export const EARTH_W = 2048;
export const EARTH_H = 1024;

const GZ_B64 = '';

let _grid: Uint8Array | null = null;
/** 2048x1024 row-major grayscale elevation (ocean 0, land 1..255). Async: the
 * grid is gzip-compressed and inflated on first use (DecompressionStream works
 * in browsers and Node ≥18). */
export async function earthGrid(): Promise<Uint8Array> {
  if (_grid) return _grid;
  const bin = atob(GZ_B64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  const ds = new DecompressionStream('gzip');
  const writer = ds.writable.getWriter();
  void writer.write(bytes); void writer.close();
  const reader = ds.readable.getReader();
  const chunks: Uint8Array[] = [];
  for (;;) { const { done, value } = await reader.read(); if (done) break; chunks.push(value as Uint8Array); }
  let len = 0; for (const c of chunks) len += c.length;
  const g = new Uint8Array(len); let o = 0; for (const c of chunks) { g.set(c, o); o += c.length; }
  _grid = g;
  return g;
}
